import type { CSSProperties, ReactNode } from 'react';
export type StepStatus = 'wait' | 'process' | 'finish' | 'error';
/**
 * 自定义节点。
 * @public
 */
export type ProgressDotRender = (iconDot: ReactNode, info: DotInfo) => ReactNode;
/**
 * 节点信息，用于 `ProgressDotRender` 的参数。
 * @public
 */
export interface DotInfo {
    index: number;
    /**
     * 标题
     */
    title: ReactNode;
    /**
     * 当前步骤状态，可选 `wait`、`process`、`finish`、`error`
     */
    status: StepStatus;
    /**
     * 子标题
     */
    subTitle: ReactNode;
    /**
     * 描述
     */
    description: ReactNode;
}
/**
 * 步骤条的方向。
 * @public
 */
export type StepDirection = 'horizontal' | 'vertical';
/**
 * 步骤条的类型。
 * @public
 */
export type StepsType = 'default' | 'navigation' | 'dot';
export interface StepsProps {
    /**
     * `className` 属性透传
     */
    className?: string;
    /**
     * `style` 属性透传
     */
    style?: CSSProperties;
    /**
     * 当前步骤，从 0 开始计数。在子 `Step` 元素中，可以通过 `status` 属性覆盖状态
     * @defaultValue 0
     */
    current?: number;
    /**
     * 起始序号，从 0 开始计数
     * @defaultValue 0
     */
    initial?: number;
    /**
     * 步骤条方向。目前支持 `horizontal` 水平和 `vertical` 竖直两种方向
     * @defaultValue `horizontal`
     */
    direction?: StepDirection;
    /**
     * 步骤条类型，有 `default`、`navigation` 和 `dot` 三种
     */
    type?: StepsType;
    /**
     * 步骤条大小，目前支持 `medium`
     * @defaultValue `medium`
     */
    size?: 'medium';
    /**
     * 当前步骤状态，可选 `wait`、`process`、`finish`、`error`
     * @defaultValue `process`
     */
    status?: StepStatus;
    /**
     * 标签放置位置，默认水平放图标下面
     * @defaultValue `vertical`
     */
    labelPlacement?: StepDirection;
    /**
     * 导航类型步骤条是否展示指示线
     * @defaultValue false
     */
    showNavIndicator?: boolean;
    /**
     * 导航类型步骤条是否展示图标
     * @defaultValue false
     */
    showIcon?: boolean;
    /**
     * 自定义节点
     */
    progressDot?: ProgressDotRender;
    /**
     * 点击切换步骤回调
     */
    onChange?: (current: number) => void;
}
